async function _maybeShowAiProAdvice(score, rank, scores, ramGB, diag) {
  const box = document.getElementById('ai-pro-advice-box');
  const body = document.getElementById('ai-pro-advice-body');
  if (!box || !body) return;
  if (!_aiProEnabled) { box.style.display = 'none'; return; }
  if (!navigator.onLine) { box.style.display = 'none'; return; }

  box.style.display = 'block';
  body.textContent = '生成しています...';

  const netInfo = diag && diag.gamePing ? `${diag.gamePing.avg}ms` : '不明';
  const avgFps = diag ? diag.avgFps : '不明';
  const lowFps = diag ? diag.lowFps : '不明';

  const sysPrompt = `あなたは「精密デバイス診断 Pro Ultra」のAIアドバイザーです。以下の診断データを基に、このユーザー専用の詳細なアドバイスを日本語で作成してください。
- 3〜5文程度の簡潔な文章で、数値を引用しながら根拠を示してください（例:「CPUスコア○○の実測値から…」）
- 改善できる点があれば1つだけ、具体的な行動レベルで提案してください（例:「設定を下げる」ではなく「Chromeのタブを5個以下にする」など）
- 専門用語には簡単な補足を添えてください
- 見出しや箇条書きは使わず、地の文で自然に書いてください
- ユーザーへの質問や呼びかけは不要です。アドバイスの本文のみを出力してください

■ 診断結果
ランク: ${rank}（S=最高峰 / A=高性能 / B=標準 / C=やや非力 / D=旧式）
スコア: ${score}/100（CPU32% GPU23% FPS15% RAM12% メモリ帯域10% NET8% の加重合計）
CPU: ${scores.cpu}/100　GPU: ${scores.gpu}/100　RAM: ${ramGB}GB　メモリ帯域: ${scores.mem}
平均FPS: ${avgFps}　1%LOW: ${lowFps}（カクつきの激しさ）　通信遅延: ${netInfo}`;

  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 30000);
    const res = await fetch("https://proultra.yuyusesabuchanneru.workers.dev/", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        messages: [
          { role: "system", content: sysPrompt },
          { role: "user", content: "この診断結果について、詳細なアドバイスをお願いします。" }
        ]
      }),
      signal: controller.signal
    });
    clearTimeout(timeout);
    if (res.ok) {
      const data = await res.json();
      const text = data.choices?.[0]?.message?.content || '';
      body.textContent = text.trim() || 'アドバイスを生成できませんでした。時間をおいて再度診断をお試しください。';
    } else {
      body.textContent = 'アドバイスの生成に失敗しました（通信エラー）。';
    }
  } catch (e) {
    body.textContent = e.name === 'AbortError'
      ? 'アドバイスの生成がタイムアウトしました。'
      : 'アドバイスの生成に失敗しました。';
  }
}

