// プライベート診断機能（履歴非表示・通知なし・パスワード保護）
// ══════════════════════════════════════════════
let _privateDiagMode = false;

async function _pdHash(text, salt) {
  const enc = new TextEncoder().encode(salt + ":" + text);
  const buf = await crypto.subtle.digest("SHA-256", enc);
  return Array.from(new Uint8Array(buf)).map((b) => b.toString(16).padStart(2, "0")).join("");
}

function _pdGetSalt() {
  let s = localStorage.getItem("private_diag_salt");
  if (!s) {
    s = Array.from(crypto.getRandomValues(new Uint8Array(16))).map((b) => b.toString(16).padStart(2, "0")).join("");
    localStorage.setItem("private_diag_salt", s);
  }
  return s;
}

function _pdHasPassword() {
  return !!localStorage.getItem("private_diag_pass_hash");
}

function startPrivateDiagnostic() {
  _privateDiagMode = true;
  guardedRetry();
}

function _pdShowPasswordModal({ mode, onSuccess }) {
  const old = document.getElementById("private-pass-modal");
  old && old.remove();
  const wrap = document.createElement("div");
  wrap.id = "private-pass-modal";
  wrap.style.cssText =
    "position:fixed;inset:0;z-index:999997;background:rgba(0,0,0,0.85);display:flex;align-items:center;justify-content:center;padding:20px;box-sizing:border-box;";
  const isSetup = mode === "setup";
  wrap.innerHTML = `
    <div style="background:#1a1a1a;border:1px solid #333;border-radius:20px;padding:24px;width:100%;max-width:340px;box-sizing:border-box;">
        <div style="font-size:1.05rem;font-weight:900;color:#fff;margin-bottom:6px;">🔒 ${isSetup ? "プライベート診断のパスワードを設定" : "パスワードを入力"}</div>
        <div style="font-size:0.78rem;color:#888;margin-bottom:16px;line-height:1.6;">${isSetup ? "初回のみ設定してください。次回以降、過去の結果を確認する際に必要になりますのでお忘れなく。" : "過去のプライベート診断結果を確認するにはパスワードが必要です。"}</div>
        <input id="pd-pass-input" type="password" placeholder="パスワード" style="width:100%;padding:12px 14px;background:#111;border:1px solid #333;border-radius:12px;color:#fff;font-size:0.95rem;box-sizing:border-box;margin-bottom:${isSetup ? "10px" : "16px"};">
        ${isSetup ? '<input id="pd-pass-input2" type="password" placeholder="パスワード（確認）" style="width:100%;padding:12px 14px;background:#111;border:1px solid #333;border-radius:12px;color:#fff;font-size:0.95rem;box-sizing:border-box;margin-bottom:16px;">' : ""}
        <div id="pd-pass-error" style="color:#ff453a;font-size:0.78rem;margin-bottom:10px;display:none;"></div>
        <div style="display:flex;gap:10px;">
            <button id="pd-pass-cancel" style="flex:1;padding:12px;border-radius:12px;background:#2a2a2a;color:#aaa;border:none;font-weight:700;cursor:pointer;">キャンセル</button>
            <button id="pd-pass-submit" style="flex:1;padding:12px;border-radius:12px;background:#7c3aed;color:#fff;border:none;font-weight:800;cursor:pointer;">${isSetup ? "設定する" : "見る"}</button>
        </div>
    </div>`;
  document.body.appendChild(wrap);
  const err = wrap.querySelector("#pd-pass-error");
  wrap.querySelector("#pd-pass-cancel").onclick = () => wrap.remove();
  wrap.querySelector("#pd-pass-submit").onclick = async () => {
    const p1 = wrap.querySelector("#pd-pass-input").value;
    if (!p1) {
      err.textContent = "パスワードを入力してください";
      err.style.display = "block";
      return;
    }
    if (isSetup) {
      const p2 = wrap.querySelector("#pd-pass-input2").value;
      if (p1 !== p2) {
        err.textContent = "パスワードが一致しません";
        err.style.display = "block";
        return;
      }
      const hash = await _pdHash(p1, _pdGetSalt());
      localStorage.setItem("private_diag_pass_hash", hash);
      wrap.remove();
      onSuccess && onSuccess();
    } else {
      const hash = await _pdHash(p1, _pdGetSalt());
      if (hash === localStorage.getItem("private_diag_pass_hash")) {
        wrap.remove();
        onSuccess && onSuccess();
      } else {
        err.textContent = "パスワードが違います";
        err.style.display = "block";
      }
    }
  };
}

