    const total = weights.reduce((a,b)=>a+b,0);
    let rnd = Math.random() * total;
    let badge = pool[pool.length-1];
    for (let i=0;i<pool.length;i++) { rnd -= weights[i]; if (rnd<=0){ badge=pool[i]; break; } }
