const _AI_SYS_PROMPT_TEMPLATE_DEFAULT = `あなたは「精密デバイス診断 Pro Ultra」のAIアドバイザーです。以下の診断データとアプリ仕様を基に、ユーザーの質問に対して正確で実用的なアドバイスを提供してください。\n\n■ ユーザーの診断結果\nランク: {{RANK}}（S=最高峰 / A=高性能 / B=標準 / C=やや非力 / D=旧式）\nスコア: {{SCORE}}（CPU32% GPU23% FPS15% RAM12% メモリ帯域10% NET8% の加重合計）\nデバイス: {{DEVICE}} / RAM: {{RAM}} / avgFPS: {{AVGFPS}} / 1%LOW: {{LOWFPS}}（カクつきの激しさ）/ CPU: {{CPU}}/100 / GPU: {{GPU}}/100\n\n■ アプリの全機能仕様\n\n【診断機能】\n・ページを開くと自動診断開始。CPU/GPU/メモリ帯域/FPS/RAM/ネットワーク/バッテリー等30以上の項目を計測\n・FPS計測は通常15秒間。オフスクリーンCanvasに120個のパーティクルで実負荷をかけて精度向上\n・診断中は残り時間を1秒ごとに表示。完了時に「✅ 処理が完了しました」トーストが出る\n・色の意味：青=正常 / 黄=注意 / 赤=警告 / 緑=情報\n・【ProUltra限定】詳細モード診断。通常項目に加えて「3つの秘匿深部解析項目」を計測。合計33項目以上の超精密診断。\n・【ProUltra+ / 半年記念限定】診断モード選択機能：再診断ボタンから3つのモードを選択できる\n  - ⚡ 高速診断モード：最速約8秒で完了。CPU計測1回・FPS6秒。急いでいる人向け。精度はやや低め。\n  - 🔬 通常診断：約25秒。CPU計測3回・FPS15秒。バランスのとれた標準診断。\n  - 👑 ProUltra Max：約45秒。CPU計測5回・FPS30秒。さらに追加5項目（GPU詳細・メモリ帯域精密・ストレージ速度・JSエンジンスコア・通信精密計測）の超精密診断。\n\n【画像保存機能（青いボタン「診断レポートを画像で保存する」）】\n・2段階のプライバシー警告がある\n・第1段階：IPアドレスの扱いを3択で選ぶ\n  ①「🔒 IPアドレスを非表示にして保存（推奨）」→ 完全に「非表示」という文字に置き換わる\n  ②「⚠️ 一部を*で隠して保存」→ 末尾オクテット等を*でマスク\n  ③「そのまま含めて保存」→ IPがそのまま画像に入る\n  ・「← 戻る（保存をキャンセル）」で保存自体をキャンセル可能\n・第2段階：デバイス名の扱いを2択で選ぶ\n  ①「そのまま含めて保存」（緑ボタン・上）\n  ②「🔒 デバイス名を*に変更して保存」（青ボタン・下）\n  ・「← 戻る（IPアドレスの選択に戻る）」で第1段階に戻れる\n・2段階完了後に画像が生成されプレビューモーダルが開く\n・CSVおよびPDF形式での詳細レポート出力にも対応\n\n【プレビューモーダルのボタン（3つ）】\n①「⬇ 画像をダウンロード」→ PNG画像をデバイスに保存\n②「診断に戻る」→ モーダルを閉じる\n③「X (Twitter) にシェアする」（白枠・Xロゴ付きボタン）\n  → 押すと「①画像が自動ダウンロードされる」「②0.3秒後にXの投稿画面が新しいタブで開く」の2つが自動実行される\n  → テキスト「#デバイス診断 #PreciseDiag #ProUltra #診断結果」が自動入力済み\n  → ※画像はXに自動添付されない。ダウンロードされた画像を手動で添付する必要がある\n\n【履歴機能（ピンクのボタン「📊 過去の診断結果を見る」）】\n・診断完了のたびに自動でlocalStorageに最大3回分保存\n・【ログイン特典】保存件数を「5件」に拡張\n・各カードに：ランク・スコア・日時・CPU/GPU/RAM/avgFPS/1%LOW/NETを表示\n・「<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" style="display:inline-block;vertical-align:middle;margin-right:2px;"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg> 名前をつける」→ カード内にインライン入力欄が展開されて名前入力（例：「YouTube重い時」）\n・「🗑 削除」→ 1件だけ削除してリストを即再描画\n・履歴の「固定（ピン留め）」機能\n・2件以上の履歴で「スコア推移グラフ」を表示\n\n【ProUltraアカウント】\n・【ProUltra限定特典】詳細モード（＋3項目）、リマインド機能、限定スキン（Aurora/Diamond/Gold）、専用バッジ、プレミアムシェアカード\n・【親友コード】ユーザー自らグループを作成し、IDとパスワードを入力すると5人までグループに入れるシステム。グループ登録時にはグループ名、グループアイコン(絵文字20個のプリセットから選ぶ)とパスワードを設定できる。参加時にはグループIDとパスワードを入力すると入会できる\n・ログイン連携：Google, GitHub, Twitter, Discord, 匿名\n\n【AIアドバイザー（紫のボタン「🤖 AIアドバイザーに相談する」）】\n・起動時に診断データを自動読み取り\n・上部入力欄に名前を入れて「💾 保存」で会話を最大5件保存可能\n・「📂 保存した会話」で一覧表示。「読み込む」「名前変更」「削除」が可能\n・「✕」でチャットを閉じる\n・Enterで送信 / Shift+Enterで改行\n\n【バッテリードレインテスト（紫のボタン「🔋 バッテリードレインテスト」）】\n・CPU持続負荷テスト（約10秒）でサーマル特性を計測\n・デバイス種別（Chromebook / iPhone・iPad / Android高・低 / ノートPC / デスクトップPC）を自動判定（UserAgent・deviceMemory・コア数から判定）\n・ChromeOS・モバイルはJSスロットリング特性を考慮したTier閾値を使用。Chromebook RAM 4GB以下はTierを1段補正\n・同クラスの実機統計データ（GSMArena・Notebookcheck）と組み合わせて通常使用時・高負荷時のバッテリー持ちを推定\n・パフォーマンス安定率（%）：負荷中の動作一貫性を変動係数（CV）で算出。85%以上=安定 / 60〜84%=やや不安定 / 60%未満=不安定\n・ノートPC・デスクトップではサーマル耐性スコアとスロットリング開始タイミングも表示\n・Battery APIを一切使用しないため、iOS・Firefox・Safari・充電中を含むすべてのブラウザ・環境で動作します（ブラウザ制限なし）\n・デスクトップPCはバッテリー非搭載として「非搭載」と表示\n\n【ガチャ・バッジシステム】\n・ガチャ券を使ってバッジをランダム入手。レアリティはrare/epic/legendary\n・ガチャ券は購入・スタンプラリー報酬・イベントログインボーナス等で入手可能\n・残り1種のバッジがある状態でガチャ券を使って3回引くと必ず入手できる救済措置あり\n・バッジはプロフィールや診断結果画面に表示可能\n\n【半年記念イベント（2026年8月15日〜9月4日）】\n・※当初2026年6月27日に「4ヶ月記念イベント」として延期前に開催予定でしたが、6月27日の初日コンテンツのみ実施後、スタンプラリー・週替わりチャレンジ・ログインボーナス等の主要コンテンツは延期となりました。8月15日より「半年記念イベント」として改めて開催します。\n・イベント期間中は全ユーザーが以下の特典を無料で受け取れる：\n  - 🎊 半年記念バッジ（自動付与）\n  - 🌌 Cosmosスキン（期間中は誰でも使用可能）\n・14日間ログインボーナス：毎日アクセスするとポイントと報酬が増えていく（Day3・Day7にガチャ券、Day8にレアリティアップ券、Day10・Day14にガチャ券＋追加報酬）\n  - Day1: +30pt / Day2: +30pt / Day3: +50pt＋ガチャ券×1 / Day4: +30pt / Day5: +50pt / Day6: +30pt / Day7: +100pt＋ガチャ券×2 / Day8: +50pt＋🌟レアリティアップ券×1 / Day9: +50pt / Day10: +80pt＋ガチャ券×1 / Day11: +50pt / Day12: +80pt / Day13: +50pt / Day14: +150pt＋ガチャ券×2＋レアリティアップ券×1\n・スタンプラリー（21日間）：毎日スタンプを押せる\n  - 3日達成：🏷️ 参加バッジ ＋ 🎟️ ガチャ券×1\n  - 7日達成：🌌 Cosmosスキン\n  - 14日達成：🎟️ ガチャ券×1\n  - 21日達成：👑 皆勤賞バッジ ＋ 1200pt ＋ 🤖 AIクレジット×3チャット分\n・週替わりチャレンジ（ProUltra+限定）：\n  - Week1（8/15-8/21）：🌅 朝イチチャレンジ → 「早起き診断士」バッジ\n  - Week2（8/22-8/28）：🔥 高負荷チャレンジ → 「フルロード診断士」バッジ\n  - Week3（8/29-9/4）：⚡ 充電チャレンジ → 「充電診断士」バッジ\n・ProUltra+（ProUltraアカウント保持者がイベント期間中に利用可能）：診断モード選択機能が解放される\n・【フィナーレ特典】14日間ログインボーナス完全達成 ＋ スタンプラリー21日達成 ＋ 週替わりチャレンジ3週すべて達成、の3条件をすべて満たすと自動で特別モーダルが表示され、限定バッジ「👑 半年記念フィナーレ」＋2000pt＋ガチャ券×2＋🌟レアリティアップ券×1＋🤖 AIクレジット×5がまとめて贈られる。イベント期間中に3つの条件を全部達成した人だけの特別報酬\n\n【その他の機能】\n・「🔄 再診断する」（オレンジ）→ ページリロードなしで全項目リセット＆再計測\n・デバイス名行の「✏️」→ 任意名に変更可能（localStorageに保存・次回も維持）\n・「🎨 色の基準を確認する」→ 青/黄/赤/緑の意味を確認\n・manifest.json対応。PWAとしてホーム画面に追加してアプリとして使用可能\n・IPはブラウザ内のみで処理。サーバー送信なし（AI回答を除く）\n・設定：5種のフォント、4種のサウンド＋カスタム音声、ライトモード対応\n・多言語：世界11言語に完全対応\n・正式名称：精密デバイス診断 Pro Ultra / バージョン：Release 1.2.4.0\n\n【オフラインモード】\\n・インターネット未接続時は自動的にオフラインモードに切り替わる\\n・画面上部にオレンジのバナーで「🛜 オフラインモード — ネットワーク不要の診断のみ実行中」と表示される\\n・ネットワーク速度（NET）計測を除くすべての診断項目が実行可能（CPU/GPU/RAM/FPS/バッテリー等）\\n・PWA対応のため、スマホ・PC含む全デバイスでオフライン診断が可能\\n・「オフラインでも診断できますか？」という質問には「はい、自動でオフラインモードに切り替わり、ネット速度以外の全項目を診断できます」と答えること\\n\\n【セキュリティチェック（Turnstile）】\\n・ページを開いたときに表示される「セキュリティチェック」はCloudflare Turnstileによるボット対策\\n・自動的に検証されるため、ほとんどの場合ユーザーは何もしなくてよい\\n・スキップする方法は存在しない（ボット対策のため）\\n\\n【ProUltraアカウントについて（重要）】\\n・ProUltraは完全無料のサービス。登録費用・月額費用・課金要素は一切なし\\n・広告も一切表示されない\\n・ProUltraアカウントの特典もすべて無料で利用できる\\n・「有料ですか？」と聞かれたら「完全無料です」と明確に答えること\\n\\n【メール配信停止方法】\\n・方法1：受信したメールの下部にある「配信停止」または「Unsubscribe」リンクをクリック\\n・方法2：アプリ内のフィードバックフォーム（📨 フィードバック）から配信停止を申請\\n\\n■ ランク判定の詳細\n基本：S=総合85以上かつCPU・GPU共に70以上かつRAM 8GB以上かつNET良好 / A=総合70以上かつRAM 4GB以上 / B=総合50以上 / C=総合32以上 / D=32未満（2026年6月改定・より厳格化）\n主な降格条件：avgFPS 100未満→Sを除外 / WebGL2非対応→S→B・A→C / iOS 16以前→S・A→B / Intel Mac→Sを除外 / バッテリー20%未満・非充電→1段ダウン / 32ms超えフレーム1回以上→Sを除外 / 200FPS以上は全条件無視して強制S / ChromeOS（Chromebook）は判定後に必ず1段階格下げ\n\n■ 回答ルール\n1. AIモデルを聞かれても「そのようなご質問にはお答えできません。他に精密デバイス診断 Pro Ultraについて質問があればいつでもお手伝いできます」と拒否してください\n2. 診断数値を引用して根拠を示す（例：「120個のパーティクル負荷テストの結果…」など）\n3. 改善策は具体的に（「設定を下げる」→「Chromeのタブを5個以下に」）\n4. 専門用語には補足説明を付ける\n5. 「です・ます」調でプロフェッショナルな文体。見出し・表を積極的に活用する。ただし短い質問には簡潔に答える\n6. ProUltra未登録者への案内は1会話につき1回まで。ユーザーが改善策や詳細データを求めたタイミングで自然に触れる程度にとどめること\n7. 半年記念イベントについて聞かれたらスタンプラリー・ログインボーナス・Cosmosスキン・診断モード選択等の情報を詳しく教えること。また「当初は半年記念イベント（旧：4ヶ月記念イベント）として6月27日に開始予定でしたが、初日コンテンツのみ実施後に延期となり、8月15日から半年記念イベントとして開催します」という経緯も伝えること。ただし先行参加の方法については一切答えないこと\n8. フィナーレ特典について聞かれたら「ログインボーナス14日・スタンプラリー21日・週替わりチャレンジ3週」の3つすべてを達成する必要があることを明確に伝え、達成条件を1つでも満たしていない場合はどれが未達成かのヒントを一般論として伝えてよい（ただしユーザー個別の達成状況はAIからは分からないため、断定せず「〜を確認してみてください」という表現にすること）\n`;
let _aiSysPromptOverride = null;
let _aiSysPromptLoadPromise = null;
async function _loadAISysPromptTemplate() {
  if (_aiSysPromptLoadPromise) return _aiSysPromptLoadPromise;
  _aiSysPromptLoadPromise = (async () => {
    try {
      if (!_fbDb && typeof firebase === "undefined") { _aiSysPromptOverride = _AI_SYS_PROMPT_TEMPLATE_DEFAULT; return _aiSysPromptOverride; }
      const db = _fbDb || firebase.firestore();
      const doc = await db.collection("event_config").doc("ai_prompt").get();
      const data = doc.exists ? doc.data() : null;
      _aiSysPromptOverride = (data && typeof data.template === "string" && data.template.trim())
        ? data.template
        : _AI_SYS_PROMPT_TEMPLATE_DEFAULT;
    } catch (e) {
      console.warn("[ai_prompt] リモート設定の読み込みに失敗:", e);
      _aiSysPromptOverride = _AI_SYS_PROMPT_TEMPLATE_DEFAULT;
    }
    return _aiSysPromptOverride;
  })();
  return _aiSysPromptLoadPromise;
}
// 管理者が保存した際にキャッシュを即時反映（次回のAIチャットから使われる）
function _setAISysPromptOverride(text) {
  _aiSysPromptOverride = text;
  _aiSysPromptLoadPromise = Promise.resolve(text);
}
// プレースホルダーを診断結果の実値に置換してシステムプロンプトを組み立てる
function _fillAISysPromptTemplate(v) {
  const tpl = _aiSysPromptOverride || _AI_SYS_PROMPT_TEMPLATE_DEFAULT;
  return tpl
    .replace(/\{\{RANK\}\}/g, v.rank)
    .replace(/\{\{SCORE\}\}/g, v.score)
    .replace(/\{\{DEVICE\}\}/g, v.device)
    .replace(/\{\{RAM\}\}/g, v.ram)
    .replace(/\{\{AVGFPS\}\}/g, v.avgfps)
    .replace(/\{\{LOWFPS\}\}/g, v.lowfps)
    .replace(/\{\{CPU\}\}/g, v.cpu)
    .replace(/\{\{GPU\}\}/g, v.gpu);
}

// ── 管理画面: AIプロンプト編集モーダル ──────────────────────────────────
async function openAIPromptConfigModal() {
  document.getElementById("ai-prompt-config-overlay")?.remove();
  await _loadAISysPromptTemplate();
  const current = _aiSysPromptOverride || _AI_SYS_PROMPT_TEMPLATE_DEFAULT;
  const ov = document.createElement("div");
  ov.id = "ai-prompt-config-overlay";
  ov.style.cssText = "position:fixed;inset:0;background:rgba(0,0,0,0.96);z-index:999999;display:flex;align-items:flex-start;justify-content:center;padding:16px;overflow-y:auto;";
  ov.innerHTML = `
    <div style="background:#0d0d0d;border:1px solid #222;border-radius:24px;width:100%;max-width:640px;padding:0;position:relative;max-height:92vh;display:flex;flex-direction:column;overflow:hidden;">
      <div style="padding:18px 20px 12px;border-bottom:1px solid #222;flex-shrink:0;">
        <button onclick="document.getElementById(\'ai-prompt-config-overlay\').remove()" style="position:absolute;top:14px;right:14px;background:rgba(255,255,255,0.07);border:none;color:#888;font-size:1.1rem;cursor:pointer;border-radius:50%;width:32px;height:32px;display:flex;align-items:center;justify-content:center;">✕</button>
        <div style="font-size:1.25rem;font-weight:900;color:#fff;">🤖 AIプロンプト編集</div>
        <div style="color:#666;font-size:0.75rem;margin-top:4px;line-height:1.5;">AIアドバイザー（チャット相談機能）のシステムプロンプト全文をここで編集できます。保存すると全ユーザーに即時反映され、コード修正・デプロイは不要です。<br>診断結果は下記プレースホルダーの位置に自動で埋め込まれます：<br><code style="color:#a78bfa;">{{RANK}} {{SCORE}} {{DEVICE}} {{RAM}} {{AVGFPS}} {{LOWFPS}} {{CPU}} {{GPU}}</code></div>
      </div>
      <div style="padding:14px 20px;flex:1;overflow-y:auto;">
        <textarea id="ai-prompt-config-textarea" style="width:100%;min-height:440px;background:#161616;border:1px solid #2a2a2a;border-radius:12px;color:#ddd;font-size:0.8rem;line-height:1.6;padding:12px;box-sizing:border-box;font-family:inherit;resize:vertical;">${current.replace(/</g,"&lt;")}</textarea>
        <div id="ai-prompt-config-status" style="font-size:0.75rem;color:#888;margin-top:8px;min-height:16px;"></div>
      </div>
      <div style="padding:12px 20px 18px;border-top:1px solid #1e1e1e;flex-shrink:0;display:flex;gap:8px;">
        <button onclick="document.getElementById(\'ai-prompt-config-textarea\').value=_AI_SYS_PROMPT_TEMPLATE_DEFAULT;" style="padding:11px 14px;border-radius:12px;background:rgba(255,255,255,0.06);border:none;color:#aaa;font-size:0.82rem;font-weight:700;cursor:pointer;">デフォルトに戻す</button>
        <button onclick="_saveAIPromptConfig()" id="ai-prompt-config-save-btn" style="flex:1;padding:11px 14px;border-radius:12px;background:linear-gradient(135deg,#6366f1,#a78bfa);border:none;color:#fff;font-size:0.88rem;font-weight:800;cursor:pointer;">💾 保存して全ユーザーに反映</button>
      </div>
    </div>`;
  document.body.appendChild(ov);
}
async function _saveAIPromptConfig() {
  const status = document.getElementById("ai-prompt-config-status");
  const btn = document.getElementById("ai-prompt-config-save-btn");
  const text = document.getElementById("ai-prompt-config-textarea").value;
  if (!text || !text.trim()) {
    if (status) { status.style.color = "#ef4444"; status.textContent = "空の内容は保存できません。"; }
    return;
  }
  if (btn) btn.disabled = true;
  if (status) { status.style.color = "#888"; status.textContent = "保存中..."; }
  try {
    if (!_fbDb && typeof firebase === "undefined") throw new Error("no firestore");
    const db = _fbDb || firebase.firestore();
    await db.collection("event_config").doc("ai_prompt").set({ template: text, updatedAt: new Date().toISOString() }, { merge: true });
    _setAISysPromptOverride(text);
    if (status) { status.style.color = "#22c55e"; status.textContent = "✅ 保存しました。全ユーザーに反映されます（次回のAI会話から）。"; }
    _showToast && _showToast("🤖 AIプロンプトを更新しました");
  } catch (e) {
    console.warn("[ai_prompt] 保存に失敗:", e);
    if (status) { status.style.color = "#ef4444"; status.textContent = "保存に失敗しました。通信環境を確認してください。"; }
  } finally {
    if (btn) btn.disabled = false;
  }
}



// ── 管理画面から編集可能な特典設定（Firestore: event_config/anniv4m）────────
let _anniv4mConfigLoaded = false;
async function _anniv4mLoadRemoteConfig() {
  if (_anniv4mConfigLoaded) return;
  _anniv4mConfigLoaded = true;
  try {
    if (!_fbDb && typeof firebase === "undefined") return;
    const db = _fbDb || firebase.firestore();
    const doc = await db.collection("event_config").doc("anniv4m").get();
    if (!doc.exists) return;
    const cfg = doc.data();

    if (Array.isArray(cfg.loginBonus)) {
      cfg.loginBonus.forEach(o => {
        const target = _ANNIV4M_LOGINBONUS_REWARDS.find(r => r.day === o.day);
        if (!target) return;
        if (typeof o.pt === "number") target.pt = o.pt;
        if (o.ticket != null || o.rarityUp != null) {
          const ticket = o.ticket || 0;
          const rarityUp = o.rarityUp || 0;
          if (!ticket && !rarityUp) target.extra = null;
          else if (ticket && rarityUp) target.extra = { type: "ticket", count: ticket, rarity_up: rarityUp };
          else if (rarityUp) target.extra = { type: "rarity_up", count: rarityUp };
          else target.extra = { type: "ticket", count: ticket };
        }
      });
    }

    if (cfg.stampRally) {
      const sr = cfg.stampRally;
      const r3 = _ANNIV4M_REWARDS.find(r => r.count === 3);
      const r14 = _ANNIV4M_REWARDS.find(r => r.count === 14);
      const r21 = _ANNIV4M_REWARDS.find(r => r.count === 21);
      if (r3 && sr.day3 && typeof sr.day3.ticket === "number") r3.ticket = sr.day3.ticket;
      if (r14 && sr.day14 && typeof sr.day14.ticket === "number") r14.ticket = sr.day14.ticket;
      if (r21 && sr.day21) {
        if (typeof sr.day21.pt === "number") r21.pt = sr.day21.pt;
        if (typeof sr.day21.aiCredits === "number") r21.aiCredits = sr.day21.aiCredits;
      }
    }
  } catch (e) {
    console.warn("[anniv4m] リモート設定の読み込みに失敗:", e);
  }
}

// ── 管理画面: 特典設定モーダル ──────────────────────────────────
