async function saveAnniv4mConfig() {
  const status = document.getElementById('admin-anniv4m-status');
  const btn = document.getElementById('admin-anniv4m-save-btn');
  if (!_currentUser || _currentUser.uid !== ADMIN_UID) { status.style.color = '#f87171'; status.textContent = '管理者のみ実行できます'; return; }

  const loginBonus = [];
  document.querySelectorAll('[data-anniv4m-lb-day]').forEach(el => {
    const day = parseInt(el.getAttribute('data-anniv4m-lb-day'));
    const field = el.getAttribute('data-field');
    let entry = loginBonus.find(o => o.day === day);
    if (!entry) { entry = { day }; loginBonus.push(entry); }
    entry[field] = parseInt(el.value) || 0;
  });

  const stampRally = {
    day3:  { ticket: parseInt(document.getElementById('admin-anniv4m-sr-day3-ticket').value) || 0 },
    day14: { ticket: parseInt(document.getElementById('admin-anniv4m-sr-day14-ticket').value) || 0 },
    day21: {
      pt: parseInt(document.getElementById('admin-anniv4m-sr-day21-pt').value) || 0,
      aiCredits: parseInt(document.getElementById('admin-anniv4m-sr-day21-ai').value) || 0,
    },
  };

  btn.disabled = true; btn.textContent = '保存中...';
  status.style.color = '#888'; status.textContent = '';
  try {
    const db = _fbDb || firebase.firestore();
    await db.collection('event_config').doc('anniv4m').set({ loginBonus, stampRally, updatedAt: new Date().toISOString() }, { merge: true });
    // 現在のセッションにも即時反映
    _anniv4mConfigLoaded = false;
    await _anniv4mLoadRemoteConfig();
    status.style.color = '#34d399';
    status.textContent = '保存しました！';
  } catch (e) {
    status.style.color = '#f87171';
    status.textContent = 'エラー: ' + String(e);
  } finally {
    btn.disabled = false; btn.textContent = '保存する';
  }
}


function _anniv4mCheckLoginBonus() {
  if (!_isAnniv4mPeriod()) return;
  const today = new Date().toISOString().slice(0, 10);
  let state;
  try { state = JSON.parse(localStorage.getItem(_ANNIV4M_LOGINBONUS_KEY) || "null"); } catch { state = null; }
  if (!state) state = { lastDate: null, day: 0, claimed: [] };
  if (state.lastDate === today) return; // 本日受取済み
  if (state.day >= 14) return; // 14日完了

  const nextDay = state.day + 1;
  const reward = _ANNIV4M_LOGINBONUS_REWARDS[nextDay - 1];
  state.lastDate = today;
  state.day = nextDay;
  state.claimed.push(nextDay);
  localStorage.setItem(_ANNIV4M_LOGINBONUS_KEY, JSON.stringify(state));

  // ポイント付与
  _puPoints = (_puPoints || 0) + reward.pt;
  _savePuPoints && _savePuPoints();

  // 追加報酬：ガチャ券
  if (reward.extra?.type === "ticket" || reward.extra?.type === "rarity_up") {
    if (reward.extra.count) {
      try {
        const t = parseInt(localStorage.getItem("pu_gacha_tickets_v1") || "0") + reward.extra.count;
        localStorage.setItem("pu_gacha_tickets_v1", String(t));
      } catch {}
    }
  }
  // 追加報酬：レアリティアップ券（単独 or Day14の複合）
  const rarityUpCount = reward.extra?.type === "rarity_up"
    ? reward.extra.count
    : (reward.extra?.rarity_up || 0);
  if (rarityUpCount > 0) {
    try {
      const ru = parseInt(localStorage.getItem("pu_rarity_up_tickets_v1") || "0") + rarityUpCount;
      localStorage.setItem("pu_rarity_up_tickets_v1", String(ru));
    } catch {}
  }

  // トースト表示
  setTimeout(() => {
    let extraMsg = "";
    if (reward.extra?.type === "ticket")    extraMsg += `\n<svg width=\"16\" height=\"16\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" style=\"display:inline-block;vertical-align:middle;\"><path d=\"M2 9a3 3 0 1 1 0 6v2a2 2 0 0 0 2 2h16a2 2 0 0 0 2-2v-2a3 3 0 1 1 0-6V7a2 2 0 0 0-2-2H4a2 2 0 0 0-2 2z\"/><path d=\"M13 5v2\"/><path d=\"M13 17v2\"/><path d=\"M13 11v2\"/></svg>️ ガチャ券×${reward.extra.count}枚ゲット！`;
    if (reward.extra?.type === "rarity_up") extraMsg += `\n🌟 レアリティアップ券×${reward.extra.count}枚ゲット！`;
    if (reward.extra?.rarity_up)            extraMsg += `\n🌟 レアリティアップ券×${reward.extra.rarity_up}枚ゲット！`;
    _showPointToast
      ? _showPointToast(`🎁 ログボ Day${nextDay} +${reward.pt}pt${extraMsg}`, _puPoints)
      : _showToast && _showToast(`🎁 ログボ Day${nextDay} +${reward.pt}pt${extraMsg}`);
  }, 2500);

  // 節目の特別メッセージ
  if (nextDay === 7) {
    setTimeout(() => _showToast && _showToast("🎊 7日間ログインボーナス達成！残り7日も頑張ろう！"), 4000);
  }
  if (nextDay === 14) {
    setTimeout(() => _showToast && _showToast("<svg width=\"16\" height=\"16\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" style=\"display:inline-block;vertical-align:middle;\"><path d=\"M6 9H4.5a2.5 2.5 0 0 1 0-5H6\"/><path d=\"M18 9h1.5a2.5 2.5 0 0 0 0-5H18\"/><path d=\"M4 22h16\"/><path d=\"M10 14.66V17c0 .55-.47.98-.97 1.21C7.85 18.75 7 20.24 7 22\"/><path d=\"M14 14.66V17c0 .55.47.98.97 1.21C16.15 18.75 17 20.24 17 22\"/><path d=\"M18 2H6v7a6 6 0 0 0 12 0V2z\"/></svg> 14日間ログインボーナス完全制覇！おめでとう！"), 4000);
  }
  _anniv4mCheckFinale();
}

// ---------- フィナーレ特典（ログボ14日 + スタンプ21日 + 週替わりチャレンジ3週すべて達成） ----------
const _ANNIV4M_FINALE_KEY = "anniv4m_finale_v1";
function _anniv4mFinaleEligible() {
  const stamps = _anniv4mGetStamps();
  const stampDone = stamps.length >= 21;
  let lb;
  try { lb = JSON.parse(localStorage.getItem(_ANNIV4M_LOGINBONUS_KEY) || "null"); } catch { lb = null; }
  const loginDone = !!(lb && lb.day >= 14);
  const challengesDone = _ANNIV4M_CHALLENGES.every(c => _anniv4mChallengeCompleted(c.badge));
  return stampDone && loginDone && challengesDone;
}
function _anniv4mCheckFinale() {
  if (localStorage.getItem(_ANNIV4M_FINALE_KEY)) return;
  if (!_anniv4mFinaleEligible()) return;
  localStorage.setItem(_ANNIV4M_FINALE_KEY, "1");
  _gachaSaveBadge && _gachaSaveBadge("anniv4m_badge_finale");
  const grandPt = 2000, grandTickets = 2, grandRarityUp = 1, grandAiCredits = 5;
  try {
    const t = parseInt(localStorage.getItem("pu_gacha_tickets_v1") || "0") + grandTickets;
    localStorage.setItem("pu_gacha_tickets_v1", String(t));
    const ru = parseInt(localStorage.getItem("pu_rarity_up_tickets_v1") || "0") + grandRarityUp;
    localStorage.setItem("pu_rarity_up_tickets_v1", String(ru));
    const aiC = parseInt(localStorage.getItem("pu_ai_credits_v1") || "0") + grandAiCredits;
    localStorage.setItem("pu_ai_credits_v1", String(aiC));
  } catch {}
  const grantPoints = () => {
    if (_currentUser && _fbDb && _isProUltra) {
      _fbDb.collection("users").doc(_currentUser.uid).get().then(doc => {
        const pts = ((doc.exists ? doc.data() : {}).points || 0) + grandPt;
        _fbDb.collection("users").doc(_currentUser.uid).set({ points: pts }, { merge: true });
        _puPoints = pts;
        _addPointHistory && _addPointHistory("👑 フィナーレ特典（半年記念コンプリート）", grandPt, pts);
      }).catch(() => {});
    } else {
      _puPoints = (_puPoints || 0) + grandPt;
      _savePuPoints && _savePuPoints();
    }
  };
  grantPoints();
  setTimeout(() => _showAnniv4mFinaleModal({ pt: grandPt, tickets: grandTickets, rarityUp: grandRarityUp, aiCredits: grandAiCredits }), 500);
}
function _showAnniv4mFinaleModal(reward) {
  document.getElementById("anniv4m-finale-overlay")?.remove();
  const ov = document.createElement("div");
  ov.id = "anniv4m-finale-overlay";
  ov.style.cssText = "position:fixed;inset:0;background:rgba(0,0,0,0.92);z-index:999999;display:flex;align-items:center;justify-content:center;padding:20px;";
  ov.innerHTML = `
    <div style="background:linear-gradient(160deg,#1a0f2e 0%,#2a0f3e 55%,#150a24 100%);border:1px solid rgba(255,215,0,0.5);border-radius:24px;max-width:380px;width:100%;padding:28px 22px;text-align:center;box-shadow:0 0 60px rgba(255,61,129,0.25);">
      <div style="font-size:3rem;margin-bottom:6px;">👑</div>
      <div style="font-size:1.15rem;font-weight:900;color:#fff;margin-bottom:4px;">半年記念イベント<br>フィナーレ達成！</div>
      <div style="color:#ffd700;font-size:0.85rem;font-weight:800;margin-bottom:16px;">スタンプ21日・ログボ14日・週替わり3週<br>すべてコンプリートしました🎉</div>
      <div style="background:rgba(255,255,255,0.05);border-radius:14px;padding:14px;text-align:left;font-size:0.82rem;color:#ddd;line-height:1.9;margin-bottom:18px;">
        👑 限定バッジ「半年記念フィナーレ」<br>
        ＋ ${reward.pt}pt<br>
        ＋ ガチャ券×${reward.tickets}<br>
        ＋ 🌟レアリティアップ券×${reward.rarityUp}<br>
        ＋ 🤖 AIクレジット×${reward.aiCredits}
      </div>
      <button onclick="document.getElementById('anniv4m-finale-overlay').remove()" style="width:100%;padding:13px;border-radius:14px;background:linear-gradient(135deg,#ff3d81,#ffd700);border:none;color:#1a0f2e;font-size:0.9rem;font-weight:900;cursor:pointer;">受け取る</button>
    </div>`;
  document.body.appendChild(ov);
}

// ============================================================
// 診断結果の称号（キャッチコピー）システム
// ============================================================
function _getDiagTitle(rank, score, scores, diag, ramGb) {
  const base = (rank || "?")[0];
  const jank32 = diag?.jank32 || 0;
  const ping = diag?.gamePing?.avg;
  const rules = [
    [score >= 95,                                    "👑 伝説の怪物マシン"],
    [jank32 >= 3,                                     "🥶 カックカク戦士"],
    [scores.cpu >= 90 && scores.gpu < 50,             "🧠 頭脳明晰・非力系"],
    [scores.gpu >= 90 && scores.cpu < 50,             "🎨 グラフィック番長"],
    [ramGb >= 16,                                     "💾 メモリ無限大明神"],
    [typeof ping === "number" && ping <= 20,          "⚡ 光速通信士"],
    [scores.fps <= 20,                                "🐌 スローライフ勢"],
    [base === "S",                                    "🚀 最強スペック戦士"],
    [base === "A",                                    "🔥 ハイスペック猛者"],
    [base === "B",                                    "⚖️ 標準装備の勇者"],
    [base === "C",                                    "🐢 やや非力系戦士"],
    [base === "D",                                    "🏚️ 老兵、まだ戦えます"],
  ];
  const hit = rules.find(([cond]) => cond);
  return hit ? hit[1] : "🎮 デバイス冒険者";
}
function _renderDiagTitle(rank, score, scores, diag, ramGb) {
  const evalMsg = document.getElementById("eval-msg");
  if (!evalMsg) return;
  let badge = document.getElementById("diag-title-badge");
  if (!badge) {
    badge = document.createElement("div");
    badge.id = "diag-title-badge";
    badge.style.cssText = "display:inline-block;margin-top:8px;padding:6px 14px;border-radius:20px;background:linear-gradient(135deg,rgba(99,102,241,0.15),rgba(236,72,153,0.15));border:1px solid rgba(167,139,250,0.4);color:#c4b5fd;font-size:0.82rem;font-weight:800;";
    evalMsg.insertAdjacentElement("afterend", badge);
  }
  badge.textContent = _getDiagTitle(rank, score, scores, diag, ramGb);
}

